import io.github.resilience4j.bulkhead.annotation.Bulkhead;
import org.springframework.stereotype.Service;
import java.util.concurrent.CompletableFuture;

@Service
public class PaymentService {
    private final PaymentClient client;
    PaymentService(PaymentClient c) { client = c; }

    @Bulkhead(name = "payments", type = Bulkhead.Type.THREADPOOL,
              fallbackMethod = "paymentBusy")
    public CompletableFuture<String> processPayment(String paymentId) {
        return CompletableFuture.supplyAsync(() -> client.process(paymentId));
        // Runs in dedicated 'payments' thread pool — never starves other features
    }

    private CompletableFuture<String> paymentBusy(String id, Exception e) {
        System.out.println("[Bulkhead] Payment pool full — queuing " + id);
        return CompletableFuture.completedFuture("QUEUED");
    }

    interface PaymentClient { String process(String id); }
}

import io.github.resilience4j.bulkhead.annotation.Bulkhead;
import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.bulkhead.BulkheadFullException;
import org.springframework.stereotype.Service;

@Service
public class ZerodhaMarketDataService {
    private final MarketClient client;
    ZerodhaMarketDataService(MarketClient c) { client = c; }

    // @Bulkhead OUTER: limits concurrent access
    @Bulkhead(name = "market-data", fallbackMethod = "bulkheadFull")
    // @CircuitBreaker INNER: stops calls when market service is struggling
    @CircuitBreaker(name = "market-data", fallbackMethod = "circuitOpen")
    public MarketData getMarketData(String symbol) {
        return client.fetch(symbol);
    }

    // Called when bulkhead is FULL (too many concurrent calls):
    private MarketData bulkheadFull(String sym, BulkheadFullException e) {
        return MarketData.stale(sym);  // return stale data
    }

    // Called when circuit is OPEN (service is failing):
    private MarketData circuitOpen(String sym, Exception e) {
        return MarketData.unavailable(sym);
    }

    // ORDER MATTERS:
    // @Bulkhead (outer): first check — is the slot available?
    //   If full: bulkheadFull() called immediately (no CB check)
    // @CircuitBreaker (inner): second check — is the service healthy?
    //   If OPEN: circuitOpen() called (no real call)
    // Both need their own fallbacks!

    interface MarketClient { MarketData fetch(String s); }
    record MarketData(String symbol, String status) {
        static MarketData stale(String s)      { return new MarketData(s, "STALE"); }
        static MarketData unavailable(String s){ return new MarketData(s, "UNAVAILABLE"); }
    }
}

import io.github.resilience4j.bulkhead.BulkheadRegistry;
import io.github.resilience4j.bulkhead.Bulkhead;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;

@Service
public class BulkheadMonitor {
    private final BulkheadRegistry registry;
    BulkheadMonitor(BulkheadRegistry r) { registry = r; }

    @Scheduled(fixedRate = 30_000)
    public void logMetrics() {
        registry.getAllBulkheads().forEach(bh -> {
            Bulkhead.Metrics m = bh.getMetrics();
            System.out.printf("[Bulkhead %s] available=%d max=%d active=%d rejected=%d%n",
                bh.getName(),
                m.getAvailableConcurrentCalls(),
                m.getMaxAllowedConcurrentCalls(),
                m.getMaxAllowedConcurrentCalls() - m.getAvailableConcurrentCalls(),
                0  // rejected count tracked via event listener
            );
            double utilization = 1.0 - (double) m.getAvailableConcurrentCalls()
                / m.getMaxAllowedConcurrentCalls();
            if (utilization > 0.8) {
                System.err.printf("[Bulkhead WARN] %s is >80%% utilized (%.0f%%)%n",
                    bh.getName(), utilization * 100);
            }
        });
    }
}

