import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@SpringBootTest
class BulkheadConcurrencyTest {
    @Autowired FlipkartSearchService searchService;

    @Test
    void bulkhead_limitsTo3ConcurrentCalls() throws Exception {
        // maxConcurrentCalls=3, maxWaitDuration=0ms
        int totalThreads = 5;
        CountDownLatch allStarted = new CountDownLatch(totalThreads);
        CountDownLatch allDone    = new CountDownLatch(totalThreads);
        AtomicInteger successCount  = new AtomicInteger(0);
        AtomicInteger fallbackCount = new AtomicInteger(0);

        for (int i = 0; i < totalThreads; i++) {
            int idx = i;
            new Thread(() -> {
                allStarted.countDown();
                try { allStarted.await(); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }

                List<String> result = searchService.search("phone " + idx);
                if (result.isEmpty()) fallbackCount.incrementAndGet();
                else                  successCount.incrementAndGet();
                allDone.countDown();
            }).start();
        }

        allDone.await(5, TimeUnit.SECONDS);

        // With maxConcurrentCalls=3: at most 3 succeed, at least 2 fallback
        assertTrue(successCount.get() <= 3,  "At most 3 should succeed");
        assertTrue(fallbackCount.get() >= 2, "At least 2 should hit bulkhead");
        assertEquals(totalThreads, successCount.get() + fallbackCount.get());
    }
}

