import io.github.resilience4j.bulkhead.annotation.Bulkhead;
import io.github.resilience4j.bulkhead.BulkheadFullException;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class SwiggyOrderService {

    // Heavy feature: limited to 50 concurrent — can't starve others
    @Bulkhead(name = "order-tracking", fallbackMethod = "cachedLocation")
    public TrackingData getTracking(String orderId) { return trackingClient.fetch(orderId); }
    private TrackingData cachedLocation(String id, BulkheadFullException e) {
        return TrackingData.cached(id);
    }

    // Read-heavy: limited to 30 concurrent
    @Bulkhead(name = "restaurant-search", fallbackMethod = "topRestaurants")
    public List<Restaurant> search(String city, String cuisine) {
        return searchClient.search(city, cuisine);
    }
    private List<Restaurant> topRestaurants(String city, String cuisine, BulkheadFullException e) {
        return preloadedTopRestaurants.getOrDefault(city, List.of());
    }

    // Critical path: protected with tight limit + longer wait
    @Bulkhead(name = "payment-processing", fallbackMethod = "paymentBusy")
    public PaymentResult processPayment(String orderId, double amount) {
        return paymentClient.process(orderId, amount);
    }
    private PaymentResult paymentBusy(String id, double amt, BulkheadFullException e) {
        return PaymentResult.queued(id);
    }

    // Even when 50 tracking + 30 search slots are all occupied:
    // Payment has its own 20 slots → ALWAYS has capacity for payments!

    private final Map<String, List<Restaurant>> preloadedTopRestaurants = Map.of();
    interface TrackingClient  { TrackingData fetch(String id); }
    interface SearchClient    { List<Restaurant> search(String city, String c); }
    interface PaymentClient   { PaymentResult process(String id, double amt); }
    TrackingClient trackingClient = id -> TrackingData.cached(id);
    SearchClient   searchClient   = (c,u) -> List.of();
    PaymentClient  paymentClient  = (id,a) -> PaymentResult.queued(id);
    record TrackingData(String id, String status) { static TrackingData cached(String i) { return new TrackingData(i,"CACHED"); } }
    record Restaurant(String name) {}
    record PaymentResult(String id, String status) { static PaymentResult queued(String i) { return new PaymentResult(i,"QUEUED"); } }
}

