import io.github.resilience4j.bulkhead.BulkheadRegistry;
import io.github.resilience4j.bulkhead.Bulkhead;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import jakarta.annotation.PostConstruct;
import java.util.concurrent.atomic.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;

@Service
public class BulkheadSaturationMonitor {
    private final BulkheadRegistry registry;
    private final Map<String, AtomicLong> rejections = new ConcurrentHashMap<>();

    BulkheadSaturationMonitor(BulkheadRegistry r) { registry = r; }

    @PostConstruct
    public void listen() {
        registry.getAllBulkheads().forEach(bh -> {
            rejections.put(bh.getName(), new AtomicLong(0));
            bh.getEventPublisher().onCallRejected(e ->
                rejections.get(bh.getName()).incrementAndGet());
        });
    }

    @Scheduled(fixedRate = 60_000)
    public void alertOnHighRejections() {
        rejections.forEach((name, count) -> {
            long rejected = count.getAndSet(0);  // reset for next minute
            System.out.printf("[Bulkhead %s] rejected=%d/min%n", name, rejected);
            if (rejected > 100) {
                System.err.printf("[ALERT] Bulkhead '%s' rejecting > 100/min!%n" +
                    "Consider increasing maxConcurrentCalls%n", name);
            }
        });
    }
}

import io.github.resilience4j.bulkhead.annotation.Bulkhead;
import io.github.resilience4j.bulkhead.BulkheadFullException;
import org.springframework.stereotype.Service;

@Service
public class BookMyShowSeatService {
    private final SeatMapClient seatClient;
    private final ZonePricingClient zoneClient;

    BookMyShowSeatService(SeatMapClient s, ZonePricingClient z) {
        seatClient = s; zoneClient = z;
    }

    // Tier 1: interactive seat map (expensive)
    @Bulkhead(name = "seat-map", fallbackMethod = "zonePricingTier")
    public SeatView getInteractiveSeatMap(String eventId) {
        return SeatView.interactive(seatClient.getMap(eventId));
    }

    // Tier 2: zone pricing (cheaper, still useful)
    // Also has its own bulkhead!
    @Bulkhead(name = "zone-pricing", fallbackMethod = "loadingPlaceholder")
    SeatView zonePricingTier(String eventId, BulkheadFullException e) {
        System.out.println("[Tier 2] Seat map full — using zone pricing for " + eventId);
        return SeatView.zones(zoneClient.getZones(eventId));
    }

    // Tier 3: loading placeholder (never fails)
    SeatView loadingPlaceholder(String eventId, BulkheadFullException e) {
        System.out.println("[Tier 3] Zone pricing full — returning placeholder");
        return SeatView.loading(eventId);
    }

    interface SeatMapClient  { String getMap(String id); }
    interface ZonePricingClient { String getZones(String id); }
    record SeatView(String eventId, String type, Object data) {
        static SeatView interactive(String d){ return new SeatView(d, "INTERACTIVE", d); }
        static SeatView zones(String d)      { return new SeatView(d, "ZONES", d); }
        static SeatView loading(String id)   { return new SeatView(id, "LOADING", null); }
    }
}

