    interface CardClient { String charge(String token, double amount); }
    private final CardClient client;
    RazorpayOrchestrator(CardClient c){client=c;}

    @Bulkhead(name="rp",fallbackMethod="bhFb")
    @CircuitBreaker(name="rp",fallbackMethod="cbFb")
    @Retry(name="rp")
    public String charge(String token, double amount){
        return client.charge(token,amount);
    }
    private String bhFb(String t,double a,BulkheadFullException e){return "BULKHEAD_FULL";}
    private String cbFb(String t,double a,Exception e){return "CIRCUIT_OPEN";}
}

@SpringBootTest
class RazorpayOrchestratorTest {
    @Autowired RazorpayOrchestrator svc;
    @MockBean RazorpayOrchestrator.CardClient client;
    @Autowired CircuitBreakerRegistry reg;
    @BeforeEach void reset(){reg.circuitBreaker("rp").reset();}

    @Test void retry_succeedsOnSecondAttempt(){
        when(client.charge(any(),anyDouble()))
            .thenThrow(new RuntimeException("blip"))
            .thenReturn("APPROVED");
        assertEquals("APPROVED",svc.charge("tok_4242",999.0));
        verify(client,times(2)).charge(any(),anyDouble());
    }
    @Test void allFail_circuitFallback(){
        when(client.charge(any(),anyDouble())).thenThrow(new RuntimeException("down"));
        String result=svc.charge("tok_4242",999.0);
        // After maxAttempts: CB fallback called
