@Service
class BookMyShowReportService {
    interface ReportEngine { String generate(String type); }
    private final ReportEngine engine;
    BookMyShowReportService(ReportEngine e){engine=e;}

    @Bulkhead(name="report-gen",type=Bulkhead.Type.THREADPOOL,fallbackMethod="reportBusy")
    public CompletableFuture<String> generateReport(String reportType){
        return CompletableFuture.supplyAsync(()->engine.generate(reportType));
        // Runs in dedicated thread pool — caller returns immediately!
    }
    private CompletableFuture<String> reportBusy(String type,Exception e){
        return CompletableFuture.completedFuture("QUEUED:"+type);
    }
}

@SpringBootTest
class ReportServiceTest {
    @Autowired BookMyShowReportService svc;
    @org.springframework.boot.test.mock.mockito.MockBean BookMyShowReportService.ReportEngine engine;

    @Test void threeReports_runConcurrently() throws Exception{
        when(engine.generate(anyString())).thenAnswer(inv->{
            Thread.sleep(100);
            return "REPORT:" + inv.getArgument(0);
        });
        var f1=svc.generateReport("SALES");
        var f2=svc.generateReport("REVENUE");
        var f3=svc.generateReport("TICKETS");
        // All three run concurrently in thread pool:
        CompletableFuture.allOf(f1,f2,f3).get(5,TimeUnit.SECONDS);
        assertTrue(f1.get().startsWith("REPORT:"));
        assertTrue(f2.get().startsWith("REPORT:"));
        assertTrue(f3.get().startsWith("REPORT:"));
    }
}

