@Service
class ZFull {
    interface NSE { String order(String id); }
    private final NSE nse;
    ZFull(NSE n){nse=n;}

    // All 4 patterns, correct order (outer to inner):
    @RateLimiter(name="zf",   fallbackMethod="rateFb")
    @Bulkhead(name="zf",      fallbackMethod="bhFb")
    @CircuitBreaker(name="zf",fallbackMethod="cbFb")
    @Retry(name="zf")
    public String submit(String id){ return nse.order(id); }

    private String rateFb(String id,RequestNotPermittedException e){return "RATE_LIMITED";}
    private String bhFb(String id,BulkheadFullException e)          {return "BULKHEAD_FULL";}
    private String cbFb(String id,Exception e)                      {return "CIRCUIT_OPEN";}
}

@SpringBootTest
class ZFullTest{
    @Autowired ZFull svc;
    @MockBean ZFull.NSE nse;
    @Autowired CircuitBreakerRegistry reg;
    @BeforeEach void reset(){reg.circuitBreaker("zf").reset();}
    @Test void retry_succeeds(){
        when(nse.order(any()))
            .thenThrow(new RuntimeException("blip"))
            .thenThrow(new RuntimeException("blip"))
            .thenReturn("ACCEPTED");
        assertEquals("ACCEPTED",svc.submit("ORD-1"));
        verify(nse,times(3)).order(any());
    }
    @Test void allFail_fallback(){
        when(nse.order(any())).thenThrow(new RuntimeException("down"));
        String r=svc.submit("ORD-2");
        assertTrue(r.equals("CIRCUIT_OPEN")||r.equals("BULKHEAD_FULL")||r.equals("RATE_LIMITED"));
    }
}
